/**
 * Returns the SVG path `d` attribute string for a given Indian state or Union Territory.
 * The path data fits within a viewBox of "0 0 56 72".
 *
 * @param stateName - The name of the state or UT (e.g., "Andhra Pradesh", "Delhi")
 * @returns The SVG path `d` attribute string, or null if the state is not found
 */
export function getStateSvg(stateName: string): string | null {
  return STATE_SVG_PATHS[stateName] ?? null;
}

/**
 * Returns a list of all available state/UT names.
 */
export function getAllStateNames(): string[] {
  return Object.keys(STATE_SVG_PATHS);
}

export default STATE_SVG_PATHS;
